const axios = require('axios');
const fs = require('fs');

const rcNumber = process.argv[2];
const appId = process.env.PREMBLY_APP_ID;
const apiKey = process.env.PREMBLY_API_KEY;

if (!rcNumber) {
  console.error('Registration number is required as the first argument.');
  process.exit(1);
}

const url = 'https://api.prembly.com/api/v1/biometrics/merchant/data/verification/cac';

const headers = {
  'app-id': appId || '',
  'x-api-key': apiKey || '',
  'Content-Type': 'application/json'
};

const data = {
  company_type: 'RC',
  rc_number: rcNumber
};

axios.post(url, data, { headers })
  .then(response => {
    fs.writeFileSync('/home/user/project/output.json', JSON.stringify(response.data, null, 2));
    console.log('Verification response saved to output.json');
  })
  .catch(error => {
    const errorData = error.response ? error.response.data : { error: error.message };
    fs.writeFileSync('/home/user/project/output.json', JSON.stringify(errorData, null, 2));
    console.error('Verification failed. Response saved to output.json');
  });

